import { Box, Button, Container, FormControlLabel, Grid, Paper, Radio, TextField, Typography } from '@material-ui/core';
import { AddRounded, CheckBox } from '@material-ui/icons';
import React from 'react';

const CreateQuiz = () => {
  return (
    <Container>
      <Grid container spacing={10}>
        <Grid item xs={12}>
          Create Quiz
        </Grid>
        <Grid item xs={12}>
          <Paper>
            <TextField placeholder='Quiz title' fullWidth />
            <TextField placeholder='description' size='small' fullWidth />
          </Paper>
        </Grid>
        <Grid item xs={12}>
          <Paper>
            <TextField placeholder='Question' fullWidth />
            <FormControlLabel value="end" control={<Radio color="primary" />} label="Choices" />
          </Paper>
        </Grid>
        <Grid item xs={12}>
          <Button>Send Quiz</Button>
        </Grid>
      </Grid>
    </Container >
  );
}

export default CreateQuiz;
